<template>
  <v-menu
    v-model="menu"
    :close-on-content-click="false"
    transition="scale-transition"
    @click:outside="menu = false"
  >
    <template #activator="{ props }">
      <v-text-field
        v-bind="props"
        :append-inner-icon="clearIcon"
        @click:append-inner="clear"
        :model-value="formatDate(internalValue)"
        :rules="rules"
        :label="label"
        lazy-rules
        readonly
        color="#624fc6"
        variant="outlined"
        rounded
        :hint="hint"
        persistent-hint
        hide-details="auto"
        class="font-weight-black"
      />
    </template>
    <v-date-picker
      :model-value="internalValue"
      color="#624fc6"
      @update:modelValue="onUpdate"
      @change="menu = false"
    />
  </v-menu>
</template>

<script setup>
import { ref, watch } from "vue";

const props = defineProps({
  modelValue: [String, Number, Date],
  label: String,
  rules: {
    type: Array,
    default: () => [],
  },
  hint: String,
});

const emit = defineEmits(["update:modelValue", "clearInput"]);

const menu = ref(false);
const clearIcon = "mdi-close";
const internalValue = ref(props.modelValue);

watch(
  () => props.modelValue,
  (val) => {
    internalValue.value = val;
  },
  { immediate: true }
);

const pad = (n) => n.toString().padStart(2, "0");

const formatDate = (val) => {
  if (!val) return "";
  const d = new Date(val);
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
};

const onUpdate = (val) => {
  if (!val) return emit("update:modelValue", null);
  const d = new Date(val);
  emit(
    "update:modelValue",
    `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`
  );
};

const clear = () => {
  emit("clearInput");
};
</script>
